#include<bits/stdc++.h>
using namespace std;
int n,m,f[101][101];
int main(){
    memset(f,127,sizeof(f));
    cin>>n>>m;
    for(int i=1;i<=n;i++)f[i][i]=0;
    for(int i=1;i<=m;i++){
        int u,v,w;
        cin>>u>>v>>w;
        f[u][v]=f[v][u]=min(f[u][v],w);
    }
    for(int k=1;k<=n;k++)
        for(int i=1;i<=n;i++)
            for(int j=1;j<=n;j++)
                if(f[i][k]<1<<30 && f[k][j]<1<<30)f[i][j]=min((long long)f[i][j],(long long)f[i][k]+f[k][j]);
    for(int i=1;i<=n;i++){
        for(int j=1;j<=n;j++)cout<<f[i][j]<<' ';
        cout<<endl;
    }
    return 0;
}
